package egovframework.com.uss.mpe.service;

import java.util.List;

import org.egovframe.rte.fdl.cmmn.exception.FdlException;

public interface EgovIndvdlPgeService {

	List<IndvdlPgeVO> selectIndvdlPgeList(IndvdlPgeVO searchVO);

	int selectIndvdlPgeListCnt(IndvdlPgeVO searchVO);

	IndvdlPgeVO selectIndvdlPgeDetail(IndvdlPgeVO indvdlPgeVO) throws Exception;

	void insertIndvdlPge(IndvdlPgeVO indvdlPgeVO) throws FdlException;

	void updateIndvdlPge(IndvdlPgeVO indvdlPgeVO);

}

/**
 * 개요 - 마이페이지에 대한 model 클래스를 정의한다.
 *
 * 상세내용 - 마이페이지의 컨텐츠아이디, 컨텐츠 명, 컨텐츠 URL, 컨텐츠 사용 여부 항목을 관리한다.
 *
 * @author 이창원
 * @version 1.0
 * @created 05-8-2009 오후 2:20:27
 */
@Getter
@Setter
public class IndvdlPgeVO extends ComDefaultVO {

	/**
	 * serialVersionUID
	 */
	private static final long serialVersionUID = 1L;

	/**
	 * 컨텐츠 아이디
	 */
	private String cntntsId;

	/**
	 * 컨텐츠 명
	 */
	@EgovNullCheck
	@Size(max = 100)
	private String cntntsNm;

	/**
	 * 컨텐츠 미리보기 URL
	 */
	@EgovNullCheck
	@Size(max = 1000)
	private String cntntsLinkUrl;

	/**
	 * 컨텐츠 URL
	 */
	@EgovNullCheck
	@Size(max = 255)
	private String cntcUrl;

	/**
	 * 컨텐츠 설명
	 */
	@EgovNullCheck
	@Size(max = 250)
	private String cntntsDc;

	/**
	 * 컨텐츠 사용 여부
	 */
	@EgovNullCheck
	private String cntntsUseAt;

}

     }

     /**
      * 컨텐츠를 등록한다.
      * @param searchVO
      * @param indvdlPgeVO
      * @param bindingResult
      * @return	"forward:/uss/mpe/selectIndvdlPgeList.do"
      * @throws Exception
      */
      @RequestMapping("/uss/mpe/insertIndvdlPge.do")
      public String insertIndvdlPge(
	  	@ModelAttribute("searchVO") IndvdlPgeVO searchVO,
		@Valid @ModelAttribute("indvdlPgeVO") IndvdlPgeVO indvdlPgeVO,
		BindingResult bindingResult) throws Exception {

  		if(bindingResult.hasErrors()){
  			return "egovframework/com/uss/mpe/EgovIndvdlPgeRegist";
  		}

          egovIndvdlPgeService.insertIndvdlPge(indvdlPgeVO);

          return "forward:/uss/mpe/selectIndvdlPgeList.do";
      }

      /**
       * 컨텐츠정보 수정 전 처리
       * @param cntntsId
       * @param searchVO
       * @param model
       * @return	"/uss/mpe/EgovIndvdlPgeUpdt"
       * @throws Exception
       */
      @RequestMapping("/uss/mpe/updateIndvdlPgeView.do")
      public String updateIndvdlPgeView(@RequestParam("cntntsId") String cntntsId ,
              @ModelAttribute("searchVO") IndvdlPgeVO searchVO, ModelMap model)
              throws Exception {

    	  IndvdlPgeVO indvdlPgeVO = new IndvdlPgeVO();

          // Primary Key 값 세팅
          indvdlPgeVO.setCntntsId(cntntsId);

          model.addAttribute("indvdlPgeVO", egovIndvdlPgeService.selectIndvdlPgeDetail(indvdlPgeVO));

          return "egovframework/com/uss/mpe/EgovIndvdlPgeUpdt";
      }

      /**
       * 컨텐츠정보를 수정한다.
       * @param searchVO
       * @param indvdlPgeVO
       * @param bindingResult
       * @return	"forward:/uss/mpe/selectIndvdlPgeList.do"
       * @throws Exception
       */
      @RequestMapping("/uss/mpe/updateIndvdlPge.do")
      public String updateIndvdlPge(
	  	@ModelAttribute("searchVO") IndvdlPgeVO searchVO,
		@Valid @ModelAttribute("indvdlPgeVO") IndvdlPgeVO indvdlPgeVO,
		BindingResult bindingResult) throws Exception {

 		if(bindingResult.hasErrors()){
  			return "egovframework/com/uss/mpe/EgovIndvdlPgeUpdt";
  		}

      	egovIndvdlPgeService.updateIndvdlPge(indvdlPgeVO);

          return "forward:/uss/mpe/selectIndvdlPgeList.do";

      }

}
